from flask import Flask, request, jsonify
from kafka import KafkaProducer
import json

app = Flask(__name__)
producer = KafkaProducer(bootstrap_servers='localhost:9092',
                         value_serializer=lambda v: json.dumps(v).encode('utf-8'))

@app.route('/publish', methods=['POST'])
def publish_message():
    topic_name = request.args.get('topic')
    message = request.json.get('message')

    if not topic_name or not message:
        return jsonify({'error': 'Topic name and message are required'}), 400

    # Validate topic name to prevent unauthorized access
    if not is_valid_topic_name(topic_name):
        return jsonify({'error': 'Invalid topic name'}), 400

    producer.send(topic_name, message)
    return jsonify({'status': 'Message sent to topic {}'.format(topic_name)}), 200

def is_valid_topic_name(topic_name):
    # Implement your own logic to validate topic names
    # For example, allow only alphanumeric characters and underscores
    return topic_name.isalnum() or '_' in topic_name

